int cmp(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}

int check(int* nums, int n, int p, int mx) {
    int cnt = 0;
    for (int i = 0; i < n - 1; ) {
        if (nums[i + 1] - nums[i] <= mx) {
            cnt++;
            i += 2;
