int minimizeMax(int* nums, int numsSize, int p) {
    qsort(nums, numsSize, sizeof(int), cmp);
    int left = 0, right = nums[numsSize - 1] - nums[0];

    while (left < right) {
        int mid = (left + right) / 2;
        if (check(nums, numsSize, p, mid)) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }

    return left;
}
